import React, { Component, Suspense } from 'react'
import { HashRouter, Route, Routes, Navigate, BrowserRouter, Outlet } from 'react-router-dom'
import { PublicRoute, PrivateRoute, ProtectedRoute } from './config/routeconfig'
import './scss/style.scss'
import businessList from './views/Business/list/businessList'
import Editor from './views/pages/editor/Editor'

const loading = (
  <div className="pt-3 text-center">
    <div className="sk-spinner sk-spinner-pulse"></div>
  </div>
)

// Containers
const DefaultLayout = React.lazy(() => import('./layout/DefaultLayout'))

// Pages
const Login = React.lazy(() => import('./views/pages/login/Login'))
const Register = React.lazy(() => import('./views/pages/register/Register'))
const Page404 = React.lazy(() => import('./views/pages/page404/Page404'))
const Page500 = React.lazy(() => import('./views/pages/page500/Page500'))

class App extends Component {
  render() {
    return (
      <BrowserRouter>
        <Suspense fallback={loading}>
          <Routes>
            <Route exact path="/login" name="Login Page" element={<PublicRoute><Login /></PublicRoute>} />
            {/* <Route exact path="/register" name="Register Page" element={<PublicRoute><Register /></PublicRoute>} /> */}
            <Route exact path="/404" name="Page 404" element={<Page404 />} />
            <Route exact path="/500" name="Page 500" element={<Page500 />} />
            {/* <Route exact path="/blog/editor/:id" name="Editor" element={<Editor/>}/> */}
            <Route
              path="*"
              name="Home"
              element={
                <ProtectedRoute>
                  <DefaultLayout />
                </ProtectedRoute>
              }
            />
          </Routes>
        </Suspense>
      </BrowserRouter>
    )
  }
}

export default App
